import{_ as t,o as n,c as a,a2 as s}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"OpenHands Architecture Analysis","description":"","frontmatter":{"title":"OpenHands Architecture Analysis","status":"complete"},"headers":[],"relativePath":"research/agents/openhands/index.md","filePath":"research/agents/openhands/index.md"}'),o={name:"research/agents/openhands/index.md"};function r(i,e,d,l,c,p){return n(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="openhands" tabindex="-1">OpenHands <a class="header-anchor" href="#openhands" aria-label="Permalink to &quot;OpenHands&quot;">​</a></h1><blockquote><p>Open-source AI-powered software development platform by <strong>All Hands AI</strong>; formerly OpenDevin.</p></blockquote><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Repository</strong></td><td><a href="https://github.com/All-Hands-AI/OpenHands" target="_blank" rel="noreferrer">https://github.com/All-Hands-AI/OpenHands</a> (54 k+ ★)</td></tr><tr><td><strong>License</strong></td><td>MIT (except <code>enterprise/</code> directory)</td></tr><tr><td><strong>Founded by</strong></td><td>Xingyao Wang, Graham Neubig, and collaborators</td></tr><tr><td><strong>Papers</strong></td><td>CodeAct (arXiv 2402.01030) · Tech Report (arXiv 2511.03690)</td></tr><tr><td><strong>Docs</strong></td><td><a href="https://docs.all-hands.dev" target="_blank" rel="noreferrer">https://docs.all-hands.dev</a></td></tr></tbody></table><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>OpenHands is a fully autonomous coding agent that can write code, fix bugs, and handle end-to-end software engineering tasks. It grew out of the academic OpenDevin project and was rebranded once it moved toward production use. The core insight — articulated in the <strong>CodeAct</strong> paper — is that consolidating every tool into a unified <em>code action space</em> (bash + IPython) dramatically outperforms JSON-based function-calling schemes for complex, multi-step engineering work.</p><p>The project occupies a unique position: it is simultaneously a <strong>research baseline</strong> (widely cited, used in SWE-bench evaluations) and a <strong>commercial product</strong> (hosted cloud, enterprise Kubernetes deployment). This dual life shapes the codebase — it is more modular and more heavily abstracted than most agent projects, but also carries the complexity that comes with supporting five distinct product surfaces from one engine.</p><hr><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        AgentController                           │</span></span>
<span class="line"><span>│  ┌────────────┐  ┌──────────────┐  ┌─────────────────────────┐  │</span></span>
<span class="line"><span>│  │ StuckDetect│  │ StateTracker │  │ ReplayManager           │  │</span></span>
<span class="line"><span>│  └────────────┘  └──────────────┘  └─────────────────────────┘  │</span></span>
<span class="line"><span>│         │                │                     │                 │</span></span>
<span class="line"><span>│         ▼                ▼                     ▼                 │</span></span>
<span class="line"><span>│  ┌─────────────────────────────────────────────────────┐        │</span></span>
<span class="line"><span>│  │                   EventStream                        │        │</span></span>
<span class="line"><span>│  │   (central pub/sub bus — all components subscribe)   │        │</span></span>
<span class="line"><span>│  └──────────┬──────────────────────────────┬────────────┘        │</span></span>
<span class="line"><span>│             │                              │                     │</span></span>
<span class="line"><span>│      ┌──────▼───────┐              ┌───────▼────────┐           │</span></span>
<span class="line"><span>│      │   Actions     │              │  Observations   │           │</span></span>
<span class="line"><span>│      │ CmdRunAction  │              │ CmdOutputObs    │           │</span></span>
<span class="line"><span>│      │ IPythonRun    │              │ FileReadObs     │           │</span></span>
<span class="line"><span>│      │ FileRead/Write│              │ BrowserOutputObs│           │</span></span>
<span class="line"><span>│      │ FileEdit      │              │ ErrorObs        │           │</span></span>
<span class="line"><span>│      │ BrowseAction  │              │ ...             │           │</span></span>
<span class="line"><span>│      │ MCPAction     │              └─────────────────┘           │</span></span>
<span class="line"><span>│      │ AgentDelegate │                                           │</span></span>
<span class="line"><span>│      │ AgentFinish   │                                           │</span></span>
<span class="line"><span>│      └──────┬────────┘                                           │</span></span>
<span class="line"><span>└─────────────┼────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>              │  REST API</span></span>
<span class="line"><span>              ▼</span></span>
<span class="line"><span>┌─────────────────────────────────┐</span></span>
<span class="line"><span>│     Docker Sandbox Container    │</span></span>
<span class="line"><span>│  ┌───────────────────────────┐  │</span></span>
<span class="line"><span>│  │  action_execution_server  │  │</span></span>
<span class="line"><span>│  │  (bash, IPython, browser) │  │</span></span>
<span class="line"><span>│  └───────────────────────────┘  │</span></span>
<span class="line"><span>└─────────────────────────────────┘</span></span></code></pre></div><h3 id="event-driven-core" tabindex="-1">Event-Driven Core <a class="header-anchor" href="#event-driven-core" aria-label="Permalink to &quot;Event-Driven Core&quot;">​</a></h3><p>Everything flows through the <strong>EventStream</strong> — a publish/subscribe bus implemented in <code>openhands/events/</code>. The agent emits <strong>Actions</strong>; the runtime executes them inside the sandbox and returns <strong>Observations</strong>. The controller watches this stream, checking for stuck loops and managing state transitions.</p><p>Key action types:</p><table tabindex="0"><thead><tr><th>Action</th><th>Purpose</th></tr></thead><tbody><tr><td><code>CmdRunAction</code></td><td>Execute a shell command in the sandbox</td></tr><tr><td><code>IPythonRunCellAction</code></td><td>Run Python code in an IPython kernel</td></tr><tr><td><code>FileReadAction</code></td><td>Read a file from the workspace</td></tr><tr><td><code>FileWriteAction</code></td><td>Write/overwrite a file</td></tr><tr><td><code>FileEditAction</code></td><td>Apply a surgical edit (search/replace style)</td></tr><tr><td><code>BrowseInteractiveAction</code></td><td>Control a headless browser</td></tr><tr><td><code>MCPAction</code></td><td>Call an MCP-protocol tool server</td></tr><tr><td><code>AgentDelegateAction</code></td><td>Spawn a sub-agent for a subtask</td></tr><tr><td><code>AgentFinishAction</code></td><td>Signal task completion</td></tr></tbody></table><p>Each action produces a corresponding observation (<code>CmdOutputObservation</code>, <code>FileReadObservation</code>, <code>BrowserOutputObservation</code>, <code>ErrorObservation</code>, etc.).</p><h3 id="sandboxed-runtime" tabindex="-1">Sandboxed Runtime <a class="header-anchor" href="#sandboxed-runtime" aria-label="Permalink to &quot;Sandboxed Runtime&quot;">​</a></h3><p>Code execution happens inside a <strong>Docker container</strong> that runs an <code>action_execution_server</code> — an HTTP server that accepts action requests and returns observation responses. The host communicates with it over a REST API on a mapped port. Alternative runtimes exist (local, remote, Modal) but Docker is the default and most battle-tested.</p><p>The sandbox provides:</p><ul><li>Full Linux environment with apt/pip</li><li>Persistent filesystem across the task</li><li>Headless Chromium for browser actions</li><li>IPython kernel for Python execution</li><li>Network isolation (configurable)</li></ul><h3 id="memory-context-management" tabindex="-1">Memory &amp; Context Management <a class="header-anchor" href="#memory-context-management" aria-label="Permalink to &quot;Memory &amp; Context Management&quot;">​</a></h3><p>The <code>ConversationMemory</code> module (<code>openhands/memory/</code>) manages what the agent sees in its context window. Because long tasks can produce thousands of events, a <strong>Condenser</strong> system compresses history using multiple strategies:</p><ul><li><strong>Recent-events condenser</strong> — keep only the last N events</li><li><strong>LLM-summary condenser</strong> — ask the LLM to summarize older history</li><li><strong>Structured condenser</strong> — preserve action/observation pairs, drop filler</li><li><strong>Hybrid</strong> — combine strategies with configurable thresholds</li></ul><p>This is one of the more sophisticated context management systems in the open-source agent space.</p><h3 id="microagents" tabindex="-1">Microagents <a class="header-anchor" href="#microagents" aria-label="Permalink to &quot;Microagents&quot;">​</a></h3><p>Microagents are a knowledge-injection mechanism. They are markdown files that get prepended to the agent&#39;s prompt based on triggers:</p><ul><li><strong>Repo microagents</strong> — <code>.openhands/microagents/</code> in the target repo; activated by keyword matching against the user&#39;s task description</li><li><strong>Global microagents</strong> — shipped with OpenHands; general-purpose knowledge (e.g., &quot;how to use git&quot;, &quot;debugging tips&quot;)</li><li><strong>Task microagents</strong> — specialized sub-agents that can be delegated to</li></ul><p>This system is loosely analogous to Cursor Rules or AGENTS.md files but with keyword-based activation rather than always-on injection.</p><hr><h2 id="product-ecosystem" tabindex="-1">Product Ecosystem <a class="header-anchor" href="#product-ecosystem" aria-label="Permalink to &quot;Product Ecosystem&quot;">​</a></h2><p>OpenHands ships five product surfaces from a single engine:</p><table tabindex="0"><thead><tr><th>Surface</th><th>Description</th><th>Analogue</th></tr></thead><tbody><tr><td><strong>Software Agent SDK</strong></td><td>Composable Python library (<code>pip install openhands-ai</code>)</td><td>—</td></tr><tr><td><strong>CLI</strong></td><td>Terminal agent; works with any LiteLLM-supported model</td><td>Claude Code, Codex</td></tr><tr><td><strong>Local GUI</strong></td><td>REST API + React SPA; run locally via Docker Compose</td><td>Devin, Jules</td></tr><tr><td><strong>Cloud</strong></td><td>Hosted at <code>app.all-hands.dev</code>; GitHub/GitLab/Jira/Slack</td><td>Devin Cloud</td></tr><tr><td><strong>Enterprise</strong></td><td>Self-hosted via Kubernetes in customer VPC</td><td>Devin Enterprise</td></tr></tbody></table><p>The SDK is the foundational layer — everything else is a thin wrapper around it. The CLI was added more recently (mid-2025) and positions OpenHands as a direct competitor to Claude Code and OpenAI Codex CLI, with the advantage of being model-agnostic via LiteLLM.</p><hr><h2 id="source-code-structure" tabindex="-1">Source Code Structure <a class="header-anchor" href="#source-code-structure" aria-label="Permalink to &quot;Source Code Structure&quot;">​</a></h2><p>The main logic lives under <code>openhands/</code>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>openhands/</span></span>
<span class="line"><span>├── agenthub/           # Agent implementations</span></span>
<span class="line"><span>│   ├── codeact_agent/  #   CodeActAgent — primary agent, unified code actions</span></span>
<span class="line"><span>│   ├── browsing_agent/ #   BrowsingAgent — web-browsing specialist</span></span>
<span class="line"><span>│   ├── readonly_agent/ #   ReadonlyAgent — read-only analysis agent</span></span>
<span class="line"><span>│   └── loc_agent/      #   LocAgent — localization/search agent</span></span>
<span class="line"><span>├── controller/         # AgentController, Agent base class</span></span>
<span class="line"><span>│   ├── agent_controller.py</span></span>
<span class="line"><span>│   ├── stuck.py        #   StuckDetector — breaks infinite loops</span></span>
<span class="line"><span>│   └── state/          #   StateTracker, ReplayManager</span></span>
<span class="line"><span>├── events/             # Event system</span></span>
<span class="line"><span>│   ├── event.py        #   Base Event class</span></span>
<span class="line"><span>│   ├── stream.py       #   EventStream pub/sub bus</span></span>
<span class="line"><span>│   ├── action/         #   All Action types</span></span>
<span class="line"><span>│   ├── observation/    #   All Observation types</span></span>
<span class="line"><span>│   └── serialization/  #   JSON serialization for events</span></span>
<span class="line"><span>├── memory/             # Context management</span></span>
<span class="line"><span>│   ├── conversation_memory.py</span></span>
<span class="line"><span>│   └── condenser/      #   Multiple condensing strategies</span></span>
<span class="line"><span>├── microagent/         # Knowledge injection system</span></span>
<span class="line"><span>├── runtime/            # Execution environments</span></span>
<span class="line"><span>│   ├── docker/         #   Docker sandbox (default)</span></span>
<span class="line"><span>│   ├── local/          #   Local execution (no isolation)</span></span>
<span class="line"><span>│   ├── remote/         #   Remote runtime client</span></span>
<span class="line"><span>│   ├── modal/          #   Modal.com runtime</span></span>
<span class="line"><span>│   ├── action_execution_server.py  # Runs inside the container</span></span>
<span class="line"><span>│   └── browser/        #   Headless Chromium integration</span></span>
<span class="line"><span>├── llm/                # LLM integration via LiteLLM</span></span>
<span class="line"><span>│   ├── llm.py          #   Main LLM wrapper</span></span>
<span class="line"><span>│   └── retry.py        #   Retry logic, rate limiting</span></span>
<span class="line"><span>├── server/             # Web server (FastAPI) for GUI</span></span>
<span class="line"><span>│   ├── routes/         #   REST API endpoints</span></span>
<span class="line"><span>│   └── session/        #   Session management</span></span>
<span class="line"><span>└── core/               # Shared infrastructure</span></span>
<span class="line"><span>    ├── config.py       #   Configuration system</span></span>
<span class="line"><span>    ├── schema.py       #   Enums, constants</span></span>
<span class="line"><span>    ├── logger.py       #   Logging</span></span>
<span class="line"><span>    └── exceptions.py   #   Exception hierarchy</span></span></code></pre></div><h3 id="codeactagent-—-the-primary-agent" tabindex="-1">CodeActAgent — The Primary Agent <a class="header-anchor" href="#codeactagent-—-the-primary-agent" aria-label="Permalink to &quot;CodeActAgent — The Primary Agent&quot;">​</a></h3><p><code>CodeActAgent</code> is the default and most capable agent. Its design follows the CodeAct paper&#39;s thesis: rather than exposing tools as JSON-schema functions, give the agent a bash shell and an IPython kernel and let it <em>write code</em> to accomplish tasks. This means:</p><ul><li>File edits are done by writing sed/awk commands or using the built-in <code>FileEditAction</code> (which itself is a search/replace primitive)</li><li>Web browsing is done through a Python API to a headless browser</li><li>Tool use is just… writing code that calls the tool</li></ul><p>The agent also supports <code>AgentDelegateAction</code> to spawn sub-agents (e.g., delegating a browsing task to <code>BrowsingAgent</code>).</p><hr><h2 id="benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#benchmarks" aria-label="Permalink to &quot;Benchmarks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>Score / Rank</th></tr></thead><tbody><tr><td><strong>SWE-bench Verified</strong></td><td><strong>77.6%</strong> (shown in their repo badge)</td></tr><tr><td><strong>Terminal-Bench 2.0</strong></td><td>Rank #49 (Claude Opus 4.5, 51.9%)</td></tr><tr><td><strong>Terminal-Bench 2.0</strong></td><td>Rank #58 (GPT-5, 43.8%)</td></tr></tbody></table><p>The SWE-bench score is competitive with top proprietary agents. However, it is worth noting that SWE-bench performance depends heavily on the underlying LLM — OpenHands acts as scaffolding, so the score reflects the combined system (agent</p><ul><li>model). The 77.6% figure likely uses a frontier model (Claude Sonnet 4 or similar).</li></ul><p>Terminal-Bench results are more modest, which is consistent with terminal-heavy benchmarks testing a different skill distribution (system administration, debugging, configuration) versus SWE-bench&#39;s focus on code patches.</p><hr><h2 id="comparison-with-other-agents" tabindex="-1">Comparison with Other Agents <a class="header-anchor" href="#comparison-with-other-agents" aria-label="Permalink to &quot;Comparison with Other Agents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dimension</th><th>OpenHands</th><th>Claude Code</th><th>Codex CLI</th><th>Devin</th></tr></thead><tbody><tr><td><strong>Open source</strong></td><td>✅ MIT</td><td>❌ Proprietary</td><td>✅ Apache 2.0</td><td>❌ Proprietary</td></tr><tr><td><strong>Model-agnostic</strong></td><td>✅ Via LiteLLM</td><td>❌ Claude only</td><td>❌ OpenAI only</td><td>❌ Proprietary</td></tr><tr><td><strong>Sandbox</strong></td><td>Docker container</td><td>macOS seatbelt</td><td>Docker/Firecracker</td><td>Cloud VM</td></tr><tr><td><strong>Browser actions</strong></td><td>✅ Headless Chromium</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td><strong>Sub-agent delegation</strong></td><td>✅ AgentDelegate</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td><strong>Context management</strong></td><td>Condenser system</td><td>Conversation summary</td><td>Basic truncation</td><td>Proprietary</td></tr><tr><td><strong>MCP support</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>GUI</strong></td><td>✅ Web UI</td><td>❌ Terminal only</td><td>❌ Terminal only</td><td>✅ Web UI</td></tr><tr><td><strong>Self-hostable</strong></td><td>✅</td><td>N/A</td><td>✅</td><td>Enterprise only</td></tr></tbody></table><p><strong>Strengths</strong>: Model-agnostic, full-featured (browser + terminal + file edit), strong research pedigree, multiple deployment modes, active community.</p><p><strong>Weaknesses</strong>: Docker dependency adds setup friction compared to Claude Code&#39;s zero-install experience. The abstraction layers (five product surfaces, multiple runtimes, event serialization) add complexity. Terminal-Bench scores suggest the agent scaffolding may not be as effective for non-SWE-bench-style tasks.</p><hr><h2 id="interesting-design-patterns" tabindex="-1">Interesting Design Patterns <a class="header-anchor" href="#interesting-design-patterns" aria-label="Permalink to &quot;Interesting Design Patterns&quot;">​</a></h2><h3 id="action-observation-abstraction" tabindex="-1">Action/Observation Abstraction <a class="header-anchor" href="#action-observation-abstraction" aria-label="Permalink to &quot;Action/Observation Abstraction&quot;">​</a></h3><p>The strict separation of Actions (agent intent) from Observations (environment feedback) creates a clean, serializable record of every agent step. This enables replay, debugging, and evaluation — you can re-run any task from its event stream without re-executing against the LLM.</p><h3 id="stuckdetector" tabindex="-1">StuckDetector <a class="header-anchor" href="#stuckdetector" aria-label="Permalink to &quot;StuckDetector&quot;">​</a></h3><p>The controller includes a <code>StuckDetector</code> that monitors the event stream for repeated action patterns (e.g., the agent running the same command in a loop). When detected, it injects a nudge observation to break the cycle. This is a practical solution to a common failure mode in long-running agent tasks.</p><h3 id="unified-code-action-space" tabindex="-1">Unified Code Action Space <a class="header-anchor" href="#unified-code-action-space" aria-label="Permalink to &quot;Unified Code Action Space&quot;">​</a></h3><p>Rather than defining a fixed tool schema, CodeActAgent lets the LLM write arbitrary bash/Python to accomplish goals. This is more flexible than function-calling but requires stronger models — weaker models may produce unsafe or incorrect commands. The tradeoff is central to the CodeAct thesis.</p><h3 id="runtime-abstraction" tabindex="-1">Runtime Abstraction <a class="header-anchor" href="#runtime-abstraction" aria-label="Permalink to &quot;Runtime Abstraction&quot;">​</a></h3><p>The runtime layer is abstracted behind a common interface, allowing the same agent to run in Docker locally, on a remote server, or on Modal.com. This separation of &quot;what the agent does&quot; from &quot;where it runs&quot; is well-executed and enables the multi-product strategy.</p><hr><h2 id="maturity-status" tabindex="-1">Maturity &amp; Status <a class="header-anchor" href="#maturity-status" aria-label="Permalink to &quot;Maturity &amp; Status&quot;">​</a></h2><ul><li><strong>Production-ready for cloud/enterprise use</strong> — the hosted platform at <code>app.all-hands.dev</code> is actively used, with GitHub/GitLab integrations</li><li><strong>Active development</strong> — high commit velocity, frequent releases</li><li><strong>Large community</strong> — 54k+ GitHub stars, active Discord, regular contributors</li><li><strong>Research lineage</strong> — multiple published papers, used as baseline in academic evaluations</li><li><strong>CLI is newer</strong> — the terminal experience is less polished than Claude Code but rapidly improving</li></ul><p>The project&#39;s main risk is complexity: supporting five product surfaces from one codebase creates a large surface area for bugs and makes contribution harder for newcomers. The enterprise/cloud layers also introduce licensing ambiguity (the <code>enterprise/</code> directory is excluded from MIT).</p><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Repository: <a href="https://github.com/All-Hands-AI/OpenHands" target="_blank" rel="noreferrer">https://github.com/All-Hands-AI/OpenHands</a></li><li>Documentation: <a href="https://docs.all-hands.dev" target="_blank" rel="noreferrer">https://docs.all-hands.dev</a></li><li>CodeAct Paper: <a href="https://arxiv.org/abs/2402.01030" target="_blank" rel="noreferrer">https://arxiv.org/abs/2402.01030</a></li><li>Tech Report: <a href="https://arxiv.org/abs/2511.03690" target="_blank" rel="noreferrer">https://arxiv.org/abs/2511.03690</a></li><li>Cloud Platform: <a href="https://app.all-hands.dev" target="_blank" rel="noreferrer">https://app.all-hands.dev</a></li></ul>`,68)])])}const g=t(o,[["render",r]]);export{u as __pageData,g as default};
